const express = require("express");
const router = express.Router();
const Property = require("../models/Property");
const authMiddleware = require("../middleware/auth");

// ─── GET /api/property-user/my (my properties, protected) ────
router.get("/my", authMiddleware, async (req, res) => {
  try {
    const properties = await Property.find({ owner: req.user.id })
      .populate("location")
      .sort({ createdAt: -1 });

    res.json({ success: true, properties });
  } catch (err) {
    res.status(500).json({ success: false, message: err.message });
  }
});

// ─── GET /api/property-user/:userId (public listings by user) ─
router.get("/:userId", async (req, res) => {
  try {
    const properties = await Property.find({ owner: req.params.userId, isAvailable: true })
      .populate("location")
      .populate("owner", "name email phone avatar")
      .sort({ createdAt: -1 });

    res.json({ success: true, properties });
  } catch (err) {
    res.status(500).json({ success: false, message: err.message });
  }
});

// ─── PATCH /api/property-user/:id/toggle (toggle availability) ─
router.patch("/:id/toggle", authMiddleware, async (req, res) => {
  try {
    const property = await Property.findById(req.params.id);
    if (!property) return res.status(404).json({ success: false, message: "Property not found" });

    if (property.owner.toString() !== req.user.id) {
      return res.status(403).json({ success: false, message: "Not authorized" });
    }

    property.isAvailable = !property.isAvailable;
    await property.save();

    res.json({
      success: true,
      message: `Property is now ${property.isAvailable ? "available" : "unavailable"}`,
      isAvailable: property.isAvailable,
    });
  } catch (err) {
    res.status(500).json({ success: false, message: err.message });
  }
});

module.exports = router;